var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"무척이나 혼란스러운 표정이시군요.","JPN":"とても混乱しているようですね。","ENG":"You look confused.","TWN":"你的表情相當困惑。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합…….","JPN":"アハブ……","ENG":"Ahab...","TWN":"亞哈……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"우리는…… 관리국의…….","JPN":"私たちは……管理局の……","ENG":"We... The Administration...","TWN":"我們……管理局的……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이런, 아직도 기억을 떠올리려 애쓰는 건가요?","JPN":"おっと、まだ記憶を思い出そうと頑張っているのですか？","ENG":"Oh, my. Are you still trying to recall your memories?","TWN":"哎呀，還在努力回憶嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아쉽게도, 정보 말소된 기억은 쉽게 돌아오지 않습니다.","JPN":"残念ながら、情報が抹消された記憶はそう簡単には戻りません。","ENG":"Unfortunately, erased memories do not come back so easily.","TWN":"可惜的是，被抹除的記憶不會輕易恢復。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"다행스럽게도, 당신이 찾는 기억은 모두 우리가 가지고 있습니다.","JPN":"幸い、あなたが探している記憶はすべて私たちが持っています。","ENG":"Luckily, however, we have all the memories you are searching for.","TWN":"幸運的是，我們擁有你要找的所有記憶。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리와 함께하게 될 당신을 위해…… 아주 소중히 간직했죠.","JPN":"私たちと共になるであろうあなたのために……とても大事に保管していました。","ENG":"We have kept them safe for you... to join us.","TWN":"為了將要和我們一起的你……我一直珍藏著它。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 언제든 당신과 함께할 준비가 되어 있습니다.","JPN":"私たちはいつでもあなたと共になる準備ができています。","ENG":"We are ready to embrace you with open arms.","TWN":"我們隨時都準備好與你並肩作戰。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신이 깨어나기를 얼마나 학수고대했는지……!","JPN":"あなたが目覚めることをどれほど待ち望んでいたことか……！","ENG":"You don't know how long we've waited for you to wake up...!","TWN":"我有多麼地盼望你醒來……！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 동결되어 있었다는 걸 알았나?","JPN":"私が凍結されているということを知っていたのか？","ENG":"You knew I was in a cryogenic state?","TWN":"你知道我被冰封起來嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신의 기척이 사라진 것 정도는 파악하고 있었습니다.","JPN":"あなたの気配が消えたことくらいは把握済みでした。","ENG":"We were able to figure it out by detecting that your presence had disappeared.","TWN":"至少知道你的氣息消失了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 한때 짐승이었으나, 당신이 한 말을 떠올리며 정신을 되찾았습니다.","JPN":"私たちはかつて獣でしたが、あなたの言葉を思い出して正気を取り戻したのです。","ENG":"We were once beasts, but your words had brought us back to our senses.","TWN":"我們曾經是野獸，但你的話讓我們恢復理智。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"바로 당신의 말이었죠. <color=#ffd34c>모든 이름에는 힘이 담겨 있다. </color>","JPN":"それはこの言葉です。<color=#ffd34c>すべての名には力が宿っている。</color>","ENG":"Your exact words were, <color=#ffd34c>\\"All names contain power.\\"</color>","TWN":"<color=#ffd34c>所有的名字都蘊含著力量。</color>"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"<color=#ffd34c>우리는 세상의 어둠을 정화하기 위해 모인 자들이다. </color>라고.","JPN":"<color=#ffd34c>私たちは世界の闇を浄化するために集った者たちだ</color>、と。","ENG":"<color=#ffd34c>\\"We are those who have gathered to purify the world from darkness.\\"</color>","TWN":"<color=#ffd34c>我們是為淨化世界的黑暗而聚集在一起的人。</color>"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그래서 내가 깨어나자 모래 폭풍이…….","JPN":"それで私が目覚めると砂嵐が……","ENG":"So that's why there was a sandstorm when I woke up...","TWN":"所以當我醒來時才會有那場沙塵暴……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"허수 공간에서 현실로 이동하는 건 반동이 크거든요.","JPN":"虚数空間から現実に移動する時の反動は大きいですからね。","ENG":"Traversing from the imaginary space to the Normalside creates a strong recoil.","TWN":"從虛數空間移動到現世會有很大的反作用力。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이젠 침식체라는 사실을 숨기지도 않는 건가?","JPN":"もはや侵食体という事実を隠す気もないのか？","ENG":"Are you no longer hiding the fact that you're a C.O. now?","TWN":"現在也不隱藏自己是侵蝕體的事實了嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"숨기지 않은 게 아닙니다. 더 이상 당신을 혼자두지 않기 위해서 선택한 방법일 뿐이죠.","JPN":"隠していないわけではありません。もうあなたを一人にしないために選んだ方法であるだけです。","ENG":"It's not that I didn't hide it. It is merely a choice I made to not leave you alone anymore.","TWN":"我並不是想隱藏什麼。這只是我選擇的一種方式，為了不再讓你一個人孤單。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"제가 당신 옆에 있던 그 불순물을 삼킨 것도 그런 이유에서였습니다.","JPN":"私があなたの隣にいたあの不純物を飲み込んだのも、その理由からでした。","ENG":"It is also the reason why I swallowed the impurity that was beside you.","TWN":"我也是為此，才吞下你身邊的那個雜質。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 옆에 있던 불순물……?","JPN":"私の隣にいた不純物……？","ENG":"The impurity beside me?","TWN":"在我旁邊的雜質……？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤!","JPN":"アーシャ！","ENG":"Asha!","TWN":"阿莎！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"자격도 없는 년이 감히 우리의 태양 옆에 있다니요. 가당치도 않은 소리죠.","JPN":"資格もないクソ女が私たちの太陽のそばにいるなど。とんでもありません。","ENG":"How dare this unworthy girl stand beside our sun? The absurdity!","TWN":"一個沒有資格的女人怎麼敢站在我們的太陽身旁？荒謬！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};